"""
mkt-context layer — Acts chapters 16–17
Output: data/commentary/mkt-context/acts.json
Run: python3 scripts/zc-context-acts-16-17.py
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: Merge new verse entries without overwriting already-present keys — safe to re-run.
    # CHANGE? If commentary JSON structure changes from {ch:{v:html}}, update this traversal.
    # VERIFY: Re-running the script should produce identical output (no duplicate or overwritten entries).
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ACTS_CH = {
"16": {
"1": "<p>Paul returns to Lystra, where he had been stoned on the first journey (Acts 14:19). Timothy's family situation — Jewish mother Eunice, Greek father (absent or deceased) — reflects the reality of Jewish diaspora families in Asia Minor who intermarried with locals while maintaining Jewish religious practice. Lystra was a Roman colony in the Lycaonian region of Galatia, a Greek-speaking area with small Jewish communities.</p>",
"2": "<p>Timothy had a reputation among the believers at Lystra and Iconium — two cities about 30 km apart connected by a Roman road. The term 'witnessed well' (emartyreito) reflects the community-based evaluation central to early church leadership selection, paralleling the approach used for the Seven in Acts 6. Cross-community reputation mattered in a world where travel was episodic and trust was built slowly.</p>",
"3": "<p>Paul circumcises Timothy for practical rather than theological reasons. As the son of a Jewish mother, Timothy was halakhically Jewish under standard Jewish legal reckoning (m. Kiddushin 3:12); his uncircumcision was therefore a deficit that would have barred him from synagogue engagement — the primary entry point for Paul's mission strategy. This stands in deliberate contrast to Titus, a full Gentile, whom Paul refused to circumcise (Gal 2:3). The distinction: Timothy's circumcision enables ministry; Titus's would have conceded the Judaizing theological claim.</p>",
"4": "<p>The Jerusalem decree (Acts 15:22–29) is now being disseminated as Paul moves west and north. The decree addressed the specific contested question of Gentile table fellowship and purity requirements — it did not require circumcision of Gentiles. Luke notes that Paul delivers the decisions (dogmata) of apostles and elders, situating local churches within the larger network of apostolic authority. This distribution function was a primary purpose of Paul's second journey alongside church planting.</p>",
"5": "<p>Luke's summary notice — churches 'strengthened in the faith and increasing in number daily' — mirrors his pattern of periodic growth reports (2:47; 6:7; 9:31; 12:24). These summaries mark the close of narrative units and serve a theological function: demonstrating that the word of God continues to advance despite opposition. 'In faith' (tē pistei) uses the article, suggesting an established body of teaching rather than simply an emotional disposition.</p>",
"6": "<p>The Phrygian and Galatian region was the interior plateau of Asia Minor — the same territory Paul had passed through on the first journey (Acts 13–14). The Spirit's prohibition against speaking the word in Asia (the Roman province, centered on Ephesus) is surprising: Asia Minor was a densely populated, highly urbanized region that Paul would eventually reach (Acts 19). Luke attributes the rerouting to the Holy Spirit without explaining the mechanism — possibly a prophetic word, possibly providential circumstances that the missionaries interpreted spiritually.</p>",
"7": "<p>Mysia was the northwest corner of Asia Minor; Bithynia was the Black Sea coast province, a wealthy region Paul had apparently planned to enter. The 'Spirit of Jesus' is an unusual formulation in Acts — one of only a few explicit 'Spirit of Jesus' references in the NT (cf. Phil 1:19). The combination of travel limitations in vv. 6–7 creates a funneling effect that leads Paul inexorably to Troas on the Aegean coast, the gateway to Europe.</p>",
"8": "<p>Troas (Alexandria Troas) was a major Aegean port city in the Troad, the northwest tip of Asia Minor. The city was a Roman colony and an important transit point between Europe and Asia. Paul would return here in Acts 20:6–12 (the Eutychus incident) and again wrote from Troas in 2 Cor 2:12. The city's strategic location as a maritime crossing point makes it the natural pivot for the westward turn of the mission.</p>",
"9": "<p>The Macedonian vision occurs at night (en horamati), a category of divine communication common in Jewish and early Christian literature (cf. Gen 46:2; Acts 18:9; 23:11). The figure identified as a Macedonian man stands without explanation — presumably recognized by dress, dialect, or self-identification. Macedonia was a Roman province north of Greece, administratively separated from Achaia. Paul reads the vision as a divine call (v. 10), consistent with his interpretive framework that the Spirit was directing the journey's geography.</p>",
"10": "<p>The famous 'we' passage begins here (16:10–17), resuming at 20:5 and continuing through the voyage to Rome in 27–28. These first-person plural sections have been debated since antiquity: they most naturally indicate that Luke (or a source using 'we') was present as a travel companion. The transition from 'they' (v. 8) to 'we' is unannounced, consistent with a travel diary incorporated into the larger narrative. The 'we' sections cluster at maritime and overland journeys, suggesting a companion who joined at Troas.</p>",
"11": "<p>Samothrace (Samothrake) was a large island in the northern Aegean, a common overnight stop for vessels sailing between Troas and Neapolis. The crossing from Troas to Neapolis (the port of Philippi) in two days with a favorable wind would have been unusually fast — suggesting to Luke divine providence. The same journey later took five days against the wind (Acts 20:6). Neapolis is the modern Kavala in northern Greece.</p>",
"12": "<p>Philippi was a Roman colony (kolonia) — a settlement of Roman citizens, often veterans, with the legal status of Roman soil. The city had been refounded by Augustus after the battle of 42 BC where he and Antony defeated Brutus and Cassius. As a colonia, Philippi had its own magistrates (duoviri/praetores), operated under Roman law, and its citizens held Roman citizenship. Luke's phrase 'a leading city of that district of Macedonia' (prōtē meris) reflects civic pride — Philippi claimed prominence, though Thessalonica was the provincial capital.</p>",
"13": "<p>The 'prayer place' (proseuchē) outside the city gate by the river reflects Jewish practice when a community lacked the ten adult male Jews required to constitute a synagogue. Proseuchē could refer to a dedicated outdoor gathering spot or a simple building. The location by water facilitated ritual washing (cf. Josephus, Ant. 14.258). The gathering consisted apparently of women, suggesting a small Jewish community without enough men for a synagogue quorum — a demographic reality in many diaspora cities.</p>",
"14": "<p>Lydia was a dealer in purple cloth (porphyropōlis) from Thyatira, a city in Lydia (Asia Minor) known for its dyeing guilds. Purple was a luxury commodity derived from murex shellfish or madder root, associated with wealth and imperial prestige. Lydia was likely a businesswoman of some means — she had a household (v. 15) and a house large enough to host Paul's team. Her origin in Thyatira suggests a connection to the textile trade networks linking Asia Minor with Macedonian markets. She is described as a 'worshiper of God' (sebomenē ton theon) — the technical term for a God-fearer, a Gentile adherent to Jewish monotheism and ethics without full conversion.</p>",
"15": "<p>Lydia's baptism with 'her household' (ton oikon autēs) is the first of three Philippian household baptisms in this chapter (cf. v. 33, the jailer's household). The household unit (oikos) was the basic social and economic cell of ancient society — it included family members, slaves, and freedpersons under the paterfamilias or, in Lydia's case, the head of household. Household conversions were normative in the ancient world: religious affiliation typically followed household leadership. Her insistence that Paul's team 'come and stay' (parabiasato) demonstrates the hospitality obligations expected of a new benefactor to the apostolic mission.</p>",
"16": "<p>The 'spirit of divination' translates pneuma pythōna — literally 'a python spirit,' referencing the Python serpent of Delphi slain by Apollo, from whose shrine the Delphic oracle operated. Pythones were itinerant ventriloquists or practitioners of oracular speech associated with Apollo's prophetic gift. Plutarch describes pythones as speaking from within the belly (Moralia 414e). Slave owners exploited such individuals commercially — the girl's owners (kyrioi) received significant income from her divination business (ergasia — 'trade/profit,' v. 16).</p>",
"17": "<p>The slave girl's proclamation — 'servants of the Most High God who proclaim to you a way of salvation' — is accurate content delivered by a compromised source, echoing the demoniac recognition of Jesus in the Gospels (Mark 1:24; Luke 4:34). 'Most High God' (theos hypsistos) was a syncretistic title used across the Hellenistic world to refer to the supreme deity — it could apply to Zeus, YHWH, or other supreme gods depending on context, making it intelligible to a Gentile audience without being specifically Jewish or Christian.</p>",
"18": "<p>Paul's exorcism — 'I command you in the name of Jesus Christ to come out of her' — is performed in absentia of Jesus and functions through the authority of the name. The delay ('many days') before Paul acts suggests either patience, strategic consideration, or distraction. The exorcism is immediate (autē tē hōra, 'at that very hour'), consistent with the power demonstrated by the name throughout Acts (3:6; 4:10; 19:13–16). The girl's liberation from the spirit simultaneously eliminates her commercial value.</p>",
"19": "<p>The economic motive for the accusation is explicit: 'their hope of profit (ergasia) was gone.' The owners drag Paul and Silas to the agora — the civic center and market where legal proceedings and public disputes were handled. The agora of Philippi was excavated and its forum and basilica are archaeologically attested. The archontes ('rulers') to whom they are brought are the local authorities, equivalent to the duoviri (praetores) of the colonial administration.</p>",
"20": "<p>The charge before the magistrates (strategoi — the term Luke uses for the duoviri coloniae, who held praetorian rank in colonies) invokes two separate allegations: disturbing the city's peace and advocating unlawful customs. The strategoi (literally 'generals,' but a common title for magistrates) were the chief executive officers of the colony. The social dimension of the accusation — 'being Jews' — frames the complaint as an ethnic and religious disruption, not merely a commercial grievance.</p>",
"21": "<p>'Customs that are not lawful for us Romans to accept or practice' invokes the Roman legal category of religio illicita — unauthorized religion. Roman law permitted Jews to practice their ancestral customs under specific protections, but proselytizing activities that disrupted the social order could be prosecuted. The emphasis on 'us Romans' (hēmin Rhōmaiois) is a pointed reminder that Philippi's status as a colonia gave its citizens Roman identity and Roman law — the implication being that Paul's preaching violated the Roman social boundary.</p>",
"22": "<p>The crowd joins the accusation — a mob dynamic familiar from Paul's other experiences (17:5; 19:28–34). The magistrates order Paul and Silas stripped and beaten with rods (rhabdizein), administered by the rhabdouchoi — the lictors who carried the fasces (bundles of rods) as symbols of magisterial authority. The fasces were functional instruments of corporal punishment. Roman citizens were legally exempt from beating without trial (lex Valeria, lex Porcia) — a right Paul will invoke in v. 37.</p>",
"23": "<p>The 'many blows' (pollas plēgas) inflicted before imprisonment matches the category of severe beating Paul references in 2 Cor 11:25 ('three times I was beaten with rods'). The jailer (desmophylax) is ordered to 'keep them securely' (asphalōs physsein) — a command that triggers the inner prison and stocks of v. 24. Prisons in the ancient world served primarily as pre-trial detention, not punitive sentences; the treatment described reflects maximum-security precaution.</p>",
"24": "<p>The inner cell (esōteron phylakēn) and stocks (xylon) represent the most secure and punitive configuration available. Stocks (podas ... eis to xylon) immobilized prisoners by locking both feet in wooden boards spread wide, causing muscle cramps and pain. The combination of beating, inner cell, and stocks constitutes extreme treatment — Luke's point is that God's deliverance will be unmistakable in contrast to the severity of the constraint.</p>",
"25": "<p>Paul and Silas praying and singing hymns (hymnoun) at midnight echoes Psalm 119:62 ('At midnight I rise to give thanks') and connects to Jewish nocturnal prayer practice. The term hymnoun covers both praise psalms and early Christian hymnic traditions (cf. Col 3:16; Eph 5:19). The other prisoners listening (epēkroōnto) creates the social audience for the miracle that follows — the entire prison population witnesses the event.</p>",
"26": "<p>The earthquake (seismos megas) opens all doors and loosens all restraints — a miraculous specificity that goes beyond typical seismic effects. Ancient prisons used chains, wooden stocks, and bolted doors; loosening every prisoner's bonds simultaneously requires more than geological explanation. Luke's telling echoes Psalm 107:14 ('he brought them out of darkness and the shadow of death and burst their bonds apart') and the earlier prison release of Acts 12:7–10, establishing a pattern of divine deliverance from unjust imprisonment.</p>",
"27": "<p>The jailer's prepared suicide reflects Roman military and civic culture's expectation that a guard whose prisoners escaped would face the same punishment as the escaped prisoners, typically execution. The principle of vicarious punishment for escapes was known in Roman law (Digest 48.3). His drawn sword (spasámenos tēn machairan) signals resolved intent — the deliverance arrives in the nick of time.</p>",
"28": "<p>Paul's cry — 'Do not harm yourself, for we are all here' — is the climactic moment: the divine liberation produced no flight. All prisoners remain. The miracle is not escape but an act of God that arrests the normal consequences of a prison break. This transforms the event from a liberation story into a demonstration of divine sovereignty that creates the conditions for the jailer's conversion.</p>",
"29": "<p>The jailer calls for lights (phōta — plural, lamps or torches), rushes in trembling (entromos), and falls before Paul and Silas. The gesture (prosepipto) indicates prostration — the posture of supplication or worship before a recognized superior power. The sequence — earthquake, intact prisoners, trembling jailer — mirrors the pattern of divine theophany producing fear in the witnesses (cf. Matt 28:4; Luke 2:9).</p>",
"30": "<p>'What must I do to be saved?' (ti me dei poiein hina sōthō) has been read both as a request for physical safety ('saved from death') and spiritual salvation. In Luke's narrative context, where sōzō functions primarily as spiritual rescue across Acts, the response in v. 31 ('believe in the Lord Jesus and you will be saved') indicates Luke understands this as a soteriological question — the jailer has recognized that something transcendent is happening and instinctively frames the right question.</p>",
"31": "<p>'Believe in the Lord Jesus and you will be saved, you and your household' extends the salvation promise to the oikos (household). The household promise is consistent with the corporate social unit of antiquity; it does not guarantee automatic salvation for family members regardless of their response, but reflects the expectation that a household head's conversion would reshape the entire household's religious practice. Compare Cornelius (10:2) and Lydia (v. 15).</p>",
"32": "<p>The word (logos) spoken to the jailer and his household enables the faith called for in v. 31. Midnight instruction in the jailer's house follows the beating and imprisonment — the urgency and hospitality invert normal hierarchies. Paul moves from prisoner to teacher in the space of an earthquake. The content of the 'word of the Lord' is not specified but presumably the basic kerygmatic proclamation of Jesus' death, resurrection, and lordship.</p>",
"33": "<p>The washing of Paul and Silas's wounds and the household baptism occur in immediate sequence. The jailer himself washing their wounds (eloúsen ... apò tōn plēgōn) reverses the power dynamic entirely — the man responsible for their security now ministers to their physical suffering. Baptism at night, in a domestic setting, with the entire household, is consistent with the early church's practice of immediate baptism on conversion without extended catechetical delay.</p>",
"34": "<p>The meal (paratheis trapezan) after baptism reflects the connection between table fellowship and community incorporation in Luke-Acts. The jailer 'rejoiced with his entire household having believed in God' — the verb pisteusas ('having believed') applies to the whole household, consistent with the conversion narrative's scope. The domestic setting of the Philippian church's origin — first Lydia's house (v. 40), then implicitly the jailer's — shapes the house-church model that would define the Philippian community (cf. Phil 4:22, 'those of Caesar's household').</p>",
"35": "<p>The magistrates send their lictors (rhabdouchoi) to release Paul and Silas in the morning. Luke gives no reason for the change of heart — contrast his usual explanatory comments. Some scholars suggest the magistrates feared the earthquake's divine implications; others that they recognized the legal irregularity of beating Roman citizens. Either way, the morning release is presented as routine administrative action, unaware that Paul is about to explode the legality of the proceedings.</p>",
"36": "<p>The jailer relays the release order and advises Paul to 'go in peace' (poreúesthe en eirēnē) — a Semitic leave-taking formula (cf. Mark 5:34; Luke 7:50) that the jailer now uses, suggesting his cultural integration into the apostolic community's idiom. The peaceful morning release stands in stark contrast to the violent arrest of the previous day.</p>",
"37": "<p>Paul's objection invokes the two key facts: (1) they are Roman citizens (Rhōmaioi hyparchontes) and (2) they were beaten publicly (dēmosiai) without trial (akatakritos). The lex Valeria (509 BC) and lex Porcia (2nd century BC) prohibited beating and imprisonment of Roman citizens without proper legal proceedings. Violation of this right was a serious political and legal embarrassment for the magistrates. Paul's demand that they come personally and escort them out — a public acknowledgment of wrongdoing — is a calculated assertion of legal dignity that protects the Philippian church from continued harassment.</p>",
"38": "<p>The magistrates are 'afraid' (ephobēthēsan) when they hear the word Rhōmaious — Roman citizenship in a Roman colony carried maximum political weight. Having violated the rights of Roman citizens, the duoviri faced potential prosecution under Roman law and serious damage to their civic careers. Their personal appearance to escort Paul and Silas out of prison is the required public demonstration that the arrest was an error — the civic equivalent of a formal apology.</p>",
"39": "<p>The personal escort by the magistrates out of prison publicly restores Paul and Silas's dignity and implicitly acknowledges their innocence. The request to 'leave the city' (exelthein ... apò tēs poleōs) is face-saving for the magistrates — they cannot continue to harbor people whose arrest was illegal, but they can frame the departure as a civic convenience. Paul complies, but not before going to Lydia's house (v. 40) — demonstrating that his departure is voluntary, not flight.</p>",
"40": "<p>The visit to Lydia's house before departure allows Paul and Silas to encourage (parekalesan) the brothers who had gathered there. Lydia's house has become the center of the nascent Philippian church — the same house that hosted Paul's initial reception now serves as the gathering point for the community. The Philippian church Paul addresses in his letter (Phil 1–4) has its origin in this house and this community. Luke's 'they' departing while 'we' drops out of the narrative (cf. 20:5 resuming 'we' at Philippi) may indicate that Luke remained in Philippi as a shepherd of this community.</p>"
},
"17": {
"1": "<p>The Via Egnatia was the major Roman road connecting the Adriatic coast (Dyrrachium/Apollonia) with Thessalonica and ultimately with Byzantium. Paul's itinerary from Philippi through Amphipolis (50 km) and Apollonia (another 50 km) to Thessalonica (another 58 km) covers approximately 160 km by road — three or four days of travel. The consistent pattern of bypassing Amphipolis and Apollonia to reach Thessalonica suggests Paul was targeting major urban centers with significant Jewish populations.</p>",
"2": "<p>Paul enters the synagogue at Thessalonica 'as was his custom' (kata to eiōthos) — establishing the synagogue mission pattern as Paul's consistent apostolic method. The three sabbaths of discussion (dialogizomenos) are a conservative estimate; Paul's letters to the Thessalonians suggest a longer residence (1 Thess 2:9 mentions working 'night and day'). The synagogue provided the most effective access to both diaspora Jews and God-fearers who were already oriented toward Jewish scripture.</p>",
"3": "<p>Paul's argument from scripture (dianigōn kai paratithemenos) involves two logical steps: first, that the Messiah had to suffer and rise (necessary from Torah and Prophets); second, that Jesus is that Messiah. The christological argument requires both demonstrating scriptural necessity and identifying Jesus as the fulfillment — the combination Luke uses throughout Acts (cf. 2:22–36; 3:18–26; 13:27–37). The interpretive method was recognizable within Second Temple Judaism's pesher and typological approaches to scripture.</p>",
"4": "<p>The converts at Thessalonica include Jews (some), a large number of God-fearing Greeks (tōn sebomenōn Hellēnōn plēthos poly), and prominent women (gynaikōn tōn prōtōn ouk oligai). The prominence of God-fearers and women of high social standing is consistent with the sociology of synagogue adherents — Hellenistic women of the upper classes were disproportionately attracted to Jewish monotheism and its ethical demands. Paul's first letter to the Thessalonians (written shortly after) addresses a predominantly Gentile community, confirming the God-fearer profile.</p>",
"5": "<p>The market crowd (agoraious tinas andras ponērous — 'evil men from the marketplace') recruited by the jealous Jews were the rough laborers and drifters who could be hired or roused for disturbance. Josephus records similar uses of crowd violence in civic disputes (Ant. 14.259). Jason's house — where Paul was being hosted — is the target, echoing the lot of the host whose guest becomes a civic threat (cf. Lot in Gen 19; Rahab in Josh 2). The attack on Jason rather than Paul (who is not found) creates legal and social pressure through the host.</p>",
"6": "<p>The charge before the politarchs (politarchas) is one of Acts' most archaeologically verified details. The title politarchas appears in inscriptions from Thessalonica and other Macedonian cities but nowhere in literary sources before the 19th century — its occurrence in Acts was once considered an error until multiple Thessalonian inscriptions confirmed its use. The charge — 'these men who have turned the world upside down' (hoi tēn oikoumenēn anastasantes) — is social disruption, casting the apostolic mission as a force for civic chaos.</p>",
"7": "<p>'Acting against the decrees of Caesar' (apenanti tōn dogmatōn Kaisaros) and 'saying there is another king, Jesus' directly invoke the charge of maiestas (treason against the emperor). After Tiberius's aggressive use of the treason law, 'another king' (basilea heteron) would trigger immediate political anxiety. The charge is technically accurate but contextually misleading: Paul's proclamation of Jesus as Lord and King was theological, not a political coup, but the terminology was indistinguishable from sedition to Roman ears.</p>",
"8": "<p>The crowd and the politarchs are 'troubled' (etaraxan) — the legal and political implications of a maiestas charge were serious. The politarchs were responsible for maintaining peace and loyalty to Rome in their district; a credible accusation of anti-imperial agitation demanded a response. Their 'taking security' (labontes to hikanon) from Jason and others was a legal instrument — a surety bond guaranteeing that the named individuals would not repeat the disturbance. This effectively expelled Paul from Thessalonica by legal mechanism.</p>",
"9": "<p>The security (hikanon) demanded from Jason functions as a bail bond or recognizance — Jason pledged financial or personal liability for Paul's departure and conduct. This explains Paul's comment in 1 Thessalonians 2:18 that Satan 'hindered' his return: the legal surety made his return legally impossible without triggering Jason's financial ruin or personal jeopardy. The bond was community protection purchased at Jason's risk.</p>",
"10": "<p>The night departure from Thessalonica echoes the pattern of strategic withdrawal under persecution (cf. 9:25; 14:6). Berea (modern Veria) was about 80 km southwest of Thessalonica — off the Via Egnatia, in a less prominent location. Paul's selection of Berea over remaining on the main road reflects the need to escape the attention of the Thessalonian network. The synagogue mission continues immediately upon arrival, consistent with Paul's apostolic method regardless of the reception in the previous city.</p>",
"11": "<p>The Bereans' reputation for being 'more noble' (eugenestroi — more well-born, generous of mind) than the Thessalonians is grounded in their receptivity to scripture examination rather than social status. 'Examining the scriptures daily' (kath' hēmeran anakrinontes tas graphas) describes what appears to be a systematic study practice — the verb anakrinontes implies interrogation, investigation, not casual reading. The Berean pattern of received-with-eagerness-but-verified-by-scripture became a proverbial model for responsible theological engagement in Christian tradition.</p>",
"12": "<p>Again, prominent Greek women (tōn Hellēnidōn gynaikōn tōn euschēmonōn) and Greek men believe. The recurring pattern of upper-class women's conversion across Acts (13:50, where they oppose; 16:14, Lydia; 17:4, 12) reflects the historical reality of women's disproportionate interest in Jewish and then Christian monotheism in the Hellenistic world. Their social prominence created both opportunities (patronage, house churches) and risks (family and civic tension).</p>",
"13": "<p>The Thessalonian Jews who 'agitated and stirred up the crowds' follow Paul 80 km to Berea — a remarkable commitment reflecting the perceived threat of the apostolic mission. Their success in Berea replicates the Thessalonian pattern: crowd agitation forces departure. This inter-city coordination of opposition demonstrates that Paul's mission had regional visibility and that his opponents operated across the province of Macedonia with organized intent.</p>",
"14": "<p>Paul is sent 'to the sea' (heōs epi tēn thalassan) — the Aegean coast — while Silas and Timothy remain in Berea. The departure by sea rather than overland by the Via Egnatia suggests an attempt to evade the pursuing Thessalonian opponents. The 'brothers' who escort Paul function as security detail and navigation, ensuring his safe transit. The route — Berea to Athens by sea — would involve coastal navigation south past the Thermaic Gulf and around the Thessalian/Euboean coasts.</p>",
"15": "<p>The escorts accompany Paul all the way to Athens — an unusual distance (some 500 km by sea) that signals either the severity of the threat or the importance of ensuring Paul's arrival. The instruction to send Silas and Timothy 'as quickly as possible' reflects Paul's need for co-workers in a new, challenging city. Timothy's eventual arrival and return (1 Thess 3:1–6) filled the intelligence gap about the Thessalonian community's state — Paul's epistolary response followed.</p>",
"16": "<p>Athens in the mid-first century was no longer the political power it had been but remained the preeminent cultural and intellectual center of the Greek world. Paul's observation that the city was 'full of idols' (kateidōlon) reflects a historically accurate impression: ancient Athens was densely populated with temples, altars, statues, and cult objects. Pausanias (Description of Greece, 2nd century AD) describes hundreds of divine images throughout the city. The intellectual and religious density of Athens sets the stage for the most philosophically sophisticated speech in Acts.</p>",
"17": "<p>Paul's dual engagement — in the synagogue and in the agora — reflects Athens's unique character. The Athenian agora was the civic and commercial center but also the site of philosophical discussion since Socrates taught there. Engaging both Jews and God-fearers (kata pasan hēmeran, daily) in the synagogue, and then anyone who happened to be present in the agora, was Paul's adaptation of his strategy to Athens's particular intellectual culture. The daily (kata pasan hēmeran) engagement suggests Paul spent weeks in the agora before the Areopagus invitation.</p>",
"18": "<p>The Epicureans and Stoics were the dominant philosophical schools of the Hellenistic and Roman world. Epicureans (followers of Epicurus, 341–270 BC) taught that pleasure (ataraxia — tranquility, freedom from disturbance) was the highest good; the gods were uninvolved in human affairs, and death was simply dissolution — the soul dispersed with the body. Stoics (followers of Zeno, 334–262 BC) taught that a divine Logos (rational principle) permeated the cosmos; virtue lived in accordance with nature and reason was the highest human faculty; they held a quasi-pantheistic cosmic theology. Both schools would find Paul's message of resurrection problematic, albeit for different reasons.</p>",
"19": "<p>The Areopagus (Areios Pagos — Hill of Ares) was an ancient Athenian council with roots in the pre-democratic era. By the first century it had broad jurisdiction over public religion, education, and morality — including the right to examine new religious teachers and doctrines. 'You are bringing strange ideas to our ears' (xenizonta ... tina) and 'what does this babbler want to say?' (ti an theloi ho spermologos houtos legein) reflect the council's gatekeeping role over philosophical and religious novelty. Spermologos ('seed-picker') was an Athenian slang term for a person who picked up scraps of ideas without understanding — an intellectual scavenger.</p>",
"20": "<p>'Strange things' (xenizonta) and the desire to 'know what these things mean' reflects the Areopagus's formal function: vetting new religious ideas for their compatibility with Athenian civic and religious order. The council had ancient precedent for examining such matters — tradition held that Socrates was prosecuted for introducing 'new deities' (Apology 24b). Paul's hearing before the Areopagus is a formal inquiry, not an informal conversation, though Luke presents it with some rhetorical drama.</p>",
"21": "<p>Luke's parenthetical observation — 'all Athenians and foreigners who lived there spent their time doing nothing except talking about and hearing the latest ideas' — is a gentle but pointed stereotype with ancient support. Demosthenes had criticized Athenian fondness for novelty (Third Philippic 10); the reputation persisted. Luke's comment simultaneously explains why Paul received a formal hearing and subtly qualifies the Athenians' intellectual earnestness — curiosity about novelty is not the same as openness to truth.</p>",
"22": "<p>'Men of Athens, I observe that in every respect you are very religious' (deisidaimonesterous) — the word is carefully chosen: deisidaimōn literally means 'god-fearing' and could be either complimentary or pejorative (superstitious). Paul begins with what rhetoricians called the captatio benevolentiae — establishing common ground before introducing the distinctive claim. His observation of their religiosity is accurate (Acts 17:16) and serves as the entry point for his argument that their own religious instincts point toward the God he proclaims.</p>",
"23": "<p>The altar 'To an Unknown God' (Agnōstō Theō) is Paul's exegetical pivot. Ancient sources (Pausanias, Description of Greece 1.1.4; Diogenes Laertius 1.110) attest to altars inscribed 'to unknown gods' (plural) in Athens and elsewhere, erected as insurance against inadvertent neglect of any deity. Paul's move — treating the altar as pointing to a specific unknown God now made known — is a bold rhetorical appropriation of Athenian religious uncertainty. He takes their acknowledgment of ignorance as an opening for revelation.</p>",
"24": "<p>'The God who made the world and everything in it' (ho theos ho poiēsas ton kosmon kai panta ta en autō) grounds Paul's theology in Jewish monotheistic creation doctrine — direct opposition to both Epicurean denial of divine involvement and Stoic identification of God with the cosmos. 'Lord of heaven and earth' (kyrios ouranou kai gēs) echoes Deuteronomy 10:14 and Psalm 24:1. 'Does not live in temples made by human hands' directly challenges the entire Greek temple-cult system, the very institutions that filled Athens with divine images (v. 16).</p>",
"25": "<p>'Nor is he served by human hands as though he needed anything' contradicts the logic of ancient religion, where sacrifice and ritual served the needs of the gods — feeding, clothing, and appeasing them. Paul's formulation echoes Psalm 50:9–12 and Isaiah 40:28 — God needs nothing from humanity because he is the source of all things. The positive flip: God 'gives to all life and breath and everything' — reversing the direction of benefit. This is creation theology applied as apologetics against both polytheism and the Stoic world-soul.</p>",
"26": "<p>'From one man he made every nation' (ex henos panta ... genos anthrōpōn) is Adamic monotheism applied to the problem of ethnic diversity — the common origin of all humanity from a single ancestor undermines Greek ethnic pride and the assumption of racial hierarchy. The determination of 'appointed times and boundaries of their dwelling' (prostetagmenous kairous kai tas horotheias tēs katoikias autōn) echoes Deuteronomy 32:8 (LXX) where God sets the boundaries of nations. The Stoics had a comparable doctrine of divine providence governing human affairs.</p>",
"27": "<p>'That they should seek God, in the hope that they might feel their way toward him and find him' (zētein ton theon, ei ara ge psēlaphēseian auton kai heurоien) uses the haptic verb psēlaphаō ('feel, grope') — a vivid image of searching in partial darkness. The conditional ei ara ge ('if perhaps') acknowledges the difficulty of this search. The key theological point: 'Yet he is actually not far from each one of us' — divine immanence is the ground for the possibility of discovery. Paul is establishing that Athens's religious searching, however misdirected, was an appropriate human activity pointing toward the God who wants to be found.</p>",
"28": "<p>'In him we live and move and have our being' is attributed by Paul to 'some of your own poets.' The phrase is most likely from Epimenides of Crete (6th century BC), a legendary figure referenced in Paul's quotation of Cretans in Titus 1:12. The second line — 'for we are indeed his offspring' (tou gar kai genos esmen) — is from Aratus of Cilicia's Phaenomena 5 (3rd century BC), a Stoic astronomical poem. Paul quotes pagan poets not to endorse their cosmology but to demonstrate that creation's witness to God has left traces even in Greek philosophy and poetry, which Athens's own intellectual tradition confirms.</p>",
"29": "<p>The logical conclusion Paul draws from the poets' acknowledgment of human divine-sonship: if we are God's offspring, then God cannot be like gold, silver, or stone — an image formed by human art and imagination (enthumēseōs anthrōpou). The argument mirrors Isaiah's polemic against idolatry (Isa 44:9–20; 46:5–7) but is delivered through the logic of Greece's own philosophical and poetic tradition, not through appeal to Jewish scripture. It is an internal critique of Athenian religion using Athenian resources.</p>",
"30": "<p>'The times of ignorance God overlooked' (tous men oun chronous tēs agnoias hyperidōn) is a formulation parallel to Romans 3:25 ('in his divine forbearance he had passed over former sins'). The philosophical vocabulary — agnoia (ignorance) — connects to the Socratic tradition where moral failure is rooted in ignorance of the good. Paul appropriates the vocabulary while redefining the solution: not philosophical enlightenment but divine repentance-requiring proclamation. The command to 'repent' (metanoein) — a thoroughly Jewish and early Christian term — now applies universally to all people everywhere (panta pantachou).</p>",
"31": "<p>Paul's argument culminates in the resurrection — the point where he knows he will lose part of his audience (v. 32). The 'day he has fixed' (hēmeran en hē mellei krinein) for universal judgment through 'a man he has appointed' echoes Daniel 7 (Son of Man) and the early Christian judgment proclamation. The 'proof to all' (pistin parascon pasin) through resurrection connects the resurrection to the theme of certainty introduced in v. 23 — the formerly unknown God is now made unambiguous through a datable historical event.</p>",
"32": "<p>The response divides cleanly along the philosophical fault line. Epicureans who denied afterlife and Stoics who held only a cyclical world-soul would both have rejected bodily resurrection as philosophically impossible or incoherent. 'Some sneered' (hoi de echleuazon) — the reaction to Paul's resurrection proclamation echoes the reaction to the disciples speaking in tongues at Pentecost (2:13). 'Some said, we will hear you again' is courteous deferral — possibly genuine interest, possibly a polite dismissal consistent with the Areopagus's deliberative culture.</p>",
"33": "<p>Paul 'went out from among them' — the Areopagus hearing concludes without the formal expulsion or violence that typically closes Paul's synagogue missions. The Athenian response is the most intellectually sophisticated and the least numerically fruitful in Acts. Luke records no church planted at Athens in Acts, though 1 Cor 16:15 mentions the household of Stephanas as Achaia's firstfruits — possibly Athenians. The Areopagus speech stands as the architectonic example of Paul's cultural engagement with Greek intellectual tradition.</p>",
"34": "<p>The named converts — Dionysius the Areopagite and a woman named Damaris — are significant. A member of the Areopagus council (Dionysius) means at least one of Paul's judges became a believer — a notable conversion given the council's gatekeeping role. Dionysius became a significant figure in early Christian tradition: Eusebius records him as the first bishop of Athens (HE 3.4.11) and a large body of mystical Christian literature was pseudonymously attributed to him ('Pseudo-Dionysius the Areopagite,' c. 5th century AD). Damaris's mention alongside Dionysius signals her social prominence — anonymous women were typically not named in such conversion lists.</p>"
}
}

def main():
    existing = load_comm('mkt-context', 'acts')
    merge_comm(existing, ACTS_CH)
    save_comm('mkt-context', 'acts', existing)
    for ck in ['16', '17']:
        count = len(existing.get(ck, {}))
        print(f'Acts {ck}: {count} verses.')

if __name__ == '__main__':
    main()
